const { Sequelize, DataTypes } = require('sequelize');

async function run() {
  const sequelize = new Sequelize({
    dialect: 'sqlite',
    storage: ':memory:',
    logging: false
  });

  const Student = sequelize.define('Student', {
    name: DataTypes.STRING
  }, { timestamps: false });

  const Course = sequelize.define('Course', {
    title: DataTypes.STRING
  }, { timestamps: false });

  const Semester = sequelize.define('Semester', {
    name: DataTypes.STRING
  }, { timestamps: false });

  const Enrollment = sequelize.define('Enrollment', {
    id: {
      type: DataTypes.INTEGER,
      primaryKey: true,
      autoIncrement: true
    }
  }, { timestamps: false });

  // Super Many-to-Many associations
  // 1. Many-to-Many through Enrollment
  Student.belongsToMany(Course, { through: Enrollment });
  Course.belongsToMany(Student, { through: Enrollment });

  // 2. One-to-Many for eager loading on the junction model
  Student.hasMany(Enrollment);
  Enrollment.belongsTo(Student);
  Course.hasMany(Enrollment);
  Enrollment.belongsTo(Course);

  // 3. Association on the junction model itself
  Enrollment.belongsTo(Semester);
  Semester.hasMany(Enrollment);

  await sequelize.sync({ force: true });

  // Insert test data
  const alice = await Student.create({ name: 'Alice' });
  const math = await Course.create({ title: 'Math 101' });
  const history = await Course.create({ title: 'History 101' });
  const fall = await Semester.create({ name: 'Fall 2023' });
  const spring = await Semester.create({ name: 'Spring 2024' });

  await Enrollment.create({ StudentId: alice.id, CourseId: math.id, SemesterId: fall.id });
  await Enrollment.create({ StudentId: alice.id, CourseId: history.id, SemesterId: spring.id });

  // Query: Student -> Courses -> Enrollment -> Semester
  const student = await Student.findOne({
    where: { name: 'Alice' },
    include: [
      {
        model: Course,
        include: [
          {
            model: Enrollment,
            include: [Semester],
            where: { StudentId: alice.id }
          }
        ]
      }
    ]
  });

  console.log(JSON.stringify(student, null, 2));
}

run().catch(err => {
  console.error(err);
  process.exit(1);
});

